```class Solution {
public:
    long long minimumSteps(string s) {
        long long res = 0, left = 0, right = 0;
        for (char c : s) {
            if (c == '1') right++;
            else left++;
        }
        res = left;
        for (int i = 0; i < s.size(); i++) {
            if (s[i] == '1') res++;
        }
        return res;
    }
};```
